import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

// Material
import { makeStyles, createStyles, useTheme } from '@material-ui/core/styles';
import AppBar from '@material-ui/core/AppBar';
import Container from '@material-ui/core/Container';
import Typography from '@material-ui/core/Typography';
import useMediaQuery from '@material-ui/core/useMediaQuery';

// Icons
import { Search, Apps, Home } from '@material-ui/icons';

//Comps
import navImg from '../images/navImg.png'
import logo from '../images/logo.png'

const useStyles = makeStyles((theme: Theme) => createStyles({
	...theme.spreadThis,
	topClass: {
		textAlign: 'right'
	},
	navCont: {
		display: 'flex',
		marginBottom: '1.5rem',
		alignItems: 'center',
		[theme.breakpoints.down('sm')]: {
			marginTop: '1rem'
		}
	},
	barClass: {
		width: 25,
		marginRight: 'auto'
	},
	homeIcon: {
		color: theme.palette.secondary.light,
		padding: '.3rem .5rem',
		marginRight: '1rem',
		borderBottom: `4px solid ${theme.palette.secondary.light}`
	},
	logoComp: {
		[theme.breakpoints.down('sm')]: {
			margin: 'auto'
		}
	},
	searchCont: {
		marginLeft: '1rem',
		borderRadius: '50%',
		width: '2.5rem',
		height: '2.5rem',
		backgroundColor: 'lightgray',
		display: 'flex',
		alignItems: 'center',
		justifyContent: 'center',
		[theme.breakpoints.down('sm')]: {
			width: '2rem',
			height: '2rem',
		}
	},
	menuCont: {
		backgroundColor: theme.palette.primary.dark,
		color: 'white',
		position: 'sticky',
		overflowX: 'auto',
		overflowY: 'hidden'
	},
	titleCont: {
		display: 'flex',
		alignItems: 'baseline',
		padding: '.5rem 1rem'
	},
	stickyClass: {
		position: 'fixed'
	}
}));

const titles = [
	{ title: 'News' },
	{ title: 'International' },
	{ title: 'Politics' },
	{ title: 'Sports' },
	{ title: 'Business' },
	{ title: 'Health' },
	{ title: 'Technology' },
	{ title: 'Security' }
]

export default function Navbar(props) {

	const [ sticky, setSticky ] = useState();

	const toggleSticky = () => {
		if (window.scrollY > 150) {
	  	setSticky(true);
		} else {
			setSticky(false)
		}
	};

	useEffect(() => {
	  window.addEventListener("scroll", toggleSticky);
	}, []);

  const theme = useTheme();
  const classes = useStyles(props);
  const matches = useMediaQuery(theme.breakpoints.up('md'));

	return (
		<div>
			{
				matches ? (
					<span>
				    <Container maxWidth="lg">
							<div className={classes.topClass}>
								<Typography variant="caption" style={{ fontWeight: 'bold' }}>Join our newsletter</Typography>
								<span> | </span>
								<Typography variant="caption" style={{ fontWeight: 'bold' }}>Login or Register</Typography>
							</div>
				    </Container>
			    	<hr className={classes.hrTop} />
					</span>
		    ) : null
			}
	    <Container className={classes.navCont}>
	    	{ !matches ? <img src={navImg} alt="" className={classes.barClass} /> : null }
	    	<Link to="/" className={classes.logoComp}>
	    		<img src={logo} className={classes.logoClass} alt="MPH-logo" />
	    	</Link>
	    	<div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center' }}>    		
		    	{ matches ? <Apps color="action"  style={{ fontSize: '3rem' }} /> : null }
		    	<div className={classes.searchCont}>
		    		<Search color="disabled" />
		    	</div>
	    	</div>
	    </Container>
	    <AppBar className={sticky ? classes.stickyClass : ""} position="sticky">
		    <div className={classes.menuCont}>
		    	<Container style={{ display: 'flex', width: '100%', justifyContent: 'space-between' }}>
	    			{!matches ? <Link style={{ height: 0 }} to="/"><Home className={classes.homeIcon} /></Link> : null}
		    		{matches ? (
		    			titles.map((str, i) => {
			    			const chars = str.title.charAt(0);
			    			const words = str.title.split(chars);
			    			return( 
			    				<Link key={i} to={`/topics/${str.title.toLowerCase()}`} className={`${classes.titleCont} ${classes.linkClass}`}>
				    				<Typography variant="h6" style={{ fontWeight: 'bold' }}>{chars}</Typography>
				    				<Typography variant="body2" style={{ fontWeight: 'bold', textTransform: 'uppercase' }}>{words[1]}</Typography>
			    				</Link>
			    			)
			    		})
			    		) : (
		    			titles.map((str, i) => ( 
			    				<Link key={i} to={`/topics/${str.title.toLowerCase()}`} className={`${classes.titleCont} ${classes.linkClass}`}>
				    				<Typography variant="body2" style={{ color: 'lightgray', textTransform: 'uppercase' }}>{str.title}</Typography>
				    			</Link>
				    			)
			    		))
		    		}
		    	</Container>
		    </div>
	    </AppBar>
		</div>
	);
}
