import React from 'react';
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';

// Comps
import TopicMap from './TopicMap';
import { newsAll } from '../../util/news'
import { img1, img2, img3, img4 } from '../../images/topic'


// Topic Arrays
const { news, international, politics, sports, business, health, technology, security } = newsAll;

export default class TopicGrid extends React.Component {

	render() {


		return (
			<Grid container>
				<TopicMap pass={news} />
				<TopicMap pass={international} />
				<TopicMap pass={politics} />
				<TopicMap pass={sports} />

				<Grid className="advertSpace" item sm={12}>
					<Typography variant="h5" style={{ cursor: 'pointer', margin: 'auto', width: 'fit-content', letterSpacing: '1px', fontFamily: '"Helvetica Compressed"', textTransform: 'uppercase'}}>
						interested in Buying this space?
					</Typography>
				</Grid>

				<TopicMap pass={business} />
				<TopicMap pass={technology} />
				<TopicMap pass={health} />
				<TopicMap pass={security} />
			</Grid>
		);
	}
}
