import React from 'react';
import { Link } from 'react-router-dom';

// Material
import Container from '@material-ui/core/Container';
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';
import { makeStyles, createStyles, useTheme } from '@material-ui/core/styles';
import useMediaQuery from '@material-ui/core/useMediaQuery';

// Comps
import { img1, img2, img3, img4 } from '../../images/recent'

const useStyles = makeStyles((theme: Theme) => createStyles({
	...theme.spreadThis,
	gridCont: {
		position: 'relative',
		backgroundColor: 'white',
		[theme.breakpoints.up('sm')]: {
			marginTop: '17.5vh'
		}
	},
	fadeText: {
		position: 'absolute',
		zIndex: -1,
		top: '-10vh',
		color: 'rgba(0,0,0,.03)',
		textTransform: 'uppercase',
		[theme.breakpoints.down('sm')]: {
			top: '-15vh',
		},
		[theme.breakpoints.down('xs')]: {
			top: '-4.5vh',
		}
	},
	recentCont: {
		textTransform: 'capitalize',
		marginTop: '.5rem',
		marginBottom: '1.5rem',
		display: 'flex',
		width: '100%',
		flexWrap: 'inherit'
	},
	recentImg: {
		margin: 'auto .5rem',
		objectFit: 'cover',
		minWidth: '75px',
		height: '75px',
		maxWidth: '75px',
	},
	body: {
		display: 'flex',
		flexDirection: 'column'
	}
}));

const news = [
	{ img: img1, topic: 'security', title: 'niger delta militants threaten destruction of key states', time: '5h ago' },
	{ img: img2, topic: 'news', title: 'FRSC begins clampdown on rickety vehicles across nigeria', time: '7h ago' },
	{ img: img3, topic: 'security', title: 'FCT minister suspends abuja chief for aiding kidnappers', time: '8h ago' },
	{ img: img4, topic: 'news', title: 'atiku’s daughter revalidates her membership of APC party', time: '12h ago' }
]

export default function RecentNews(props) {

  const theme = useTheme();
  const classes = useStyles(props);
  // const matches = useMediaQuery(theme.breakpoints.up('md'));
  const matchesLG = useMediaQuery(theme.breakpoints.up('lg'));

  const rText = (
  		<span className={classes.fadeText}>
				<Typography style={{ fontFamily: '"Open Sans"', fontWeight: 'bold' }} variant={matchesLG ? 'h3' : 'h4'}><span style={{ fontSize: '120%' }}>R</span>ecent <span style={{ fontSize: '120%' }}>N</span>ews</Typography>
			</span>
		);

	return (
		<Grid item xs={12} md={4} className={classes.gridCont}>
			<Container maxWidth="lg">
				{ rText }
				{
					news.map((data, i) => (
						<Link className={classes.linkClass} to={{
							pathname: `/story/${data.title.replace(/[,-.–—"':?!$&;]/g, '').replace(/\s+/g, '-').toLowerCase()}`,
							story: data
						}}>
							<Grid className={classes.recentCont} key={i} container>
								<img src={data.img} alt="recent-img" className={classes.recentImg} />
								<div className={classes.body}>
									<Typography variant="body1">{data.title}</Typography>
									<Typography style={{ marginTop: 'auto', textTransform: 'uppercase' }} variant="caption">{data.time}</Typography>
								</div>
							</Grid>
							{ news.length !== i+1 ? <hr className={classes.newsHr} /> : null }
						</Link>
					))
				}
			</Container>
		</Grid>
	)
}