import React from 'react';
import { Link } from 'react-router-dom';
import Carousel from '@brainhubeu/react-carousel';
import '@brainhubeu/react-carousel/lib/style.css';

// Material
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';
import { makeStyles, createStyles, useTheme } from '@material-ui/core/styles';
import useMediaQuery from '@material-ui/core/useMediaQuery';

// Comps
import { img1, img2, img3, img4, img5 } from '../../images/latest'

const useStyles = makeStyles((theme: Theme) => createStyles({
	...theme.spreadThis,
	gridCont: {
		position: 'relative',
		[theme.breakpoints.up('sm')]: {
			marginTop: '17.5vh'
		}
	},
	fadeText: {
		position: 'absolute',
		zIndex: -1,
		top: '-10vh',
		color: 'rgba(0,0,0,.03)',
		textTransform: 'uppercase',
	},
	newsCont: {
		marginTop: '.5rem',
		[theme.breakpoints.up('sm')]: {
			marginRight: '1rem',
		}
	},
	imgClass: {
		width: '500px',
		height: '400px',
		objectFit: 'cover',
		[theme.breakpoints.down('sm')]: {
			height: '300px',
	    display: 'block',
	    margin: 'auto',
		},
	},
	smHr: {
		borderBottom: '0',
		borderLeft: '0',
		borderTop: '10px solid #ebebeb',
		marginBottom: '2rem'
	},
	smGrid: {
		margin: 'auto 1rem',
		minWidth: 225,
		display: 'flex',
		overflow: 'auto',
		flexDirection: 'column'
	},
	smImg: {
		width: 'auto',
		height: 125,
		objectFit: 'cover'
	}
}));

const news = [
	{ img: img1, topic: 'health', title: 'New COVID-19 Variant Detected In Nigeria, 15 Countries - NCDC', details: 'A new variant of COVID-19 has been detected in Nigeria and 15 other countries, the Nigeria Centre for Disease Control said on Thursday.', time: '10min ago' },
	{ img: img2, topic: 'international', title: 'Saudi Government Extends COVID-19 Restrictions For 20 Days', details: 'Saudi Arabia on Sunday announced a 20-day extension of precautionary measures against COVID-19, according to local media.', time: '30min ago' },
	{ img: img3, topic: 'security', title: 'Ex-DSS Official Reveals Gumi Met Bandits Near A Military Post', details: 'Security forces did not engage Kagara kidnappers to avoid collateral damage, former DSS official claims.', time: '1hr ago' },
	{ img: img4, topic: 'security', title: 'Rescued Passengers: What Bandits Did To Our Women In The Forest', details: 'Victims who were abducted from a Niger State Transport Authority (NSTA) bus last week, have narrated their experience in captivity.', time: '1hr ago' },
	{ img: img5, topic: 'international', title: 'Lebanon Starts Its COVID-19 Vaccination Drive, PM Waits Turn', details: 'Lebanon started its COVID-19 vaccination drive on Sunday by inoculating the head of critical care at its biggest public hospital.', time: '2hr ago' },
]

export default function LatestNews(props) {

  const theme = useTheme();
  const classes = useStyles(props);
  const matches = useMediaQuery(theme.breakpoints.up('md'));
  const matchesLG = useMediaQuery(theme.breakpoints.up('lg'));

  const lText = (
  		<span className={classes.fadeText}>
				<Typography style={{ fontFamily: '"Open Sans"', fontWeight: 'bold' }} variant={matchesLG ? 'h3' : 'h4'}><span style={{ fontSize: '120%' }}>L</span>atest <span style={{ fontSize: '120%' }}>N</span>ews</Typography>
			</span>
		);

	return (
		<Grid item xs={12} md={8} className={classes.gridCont}>
			{ matches ? lText : null }
			{
				matches ? (
					<Carousel autoPlay={7500} infinite={true}>
					{
						news.map((data, i) => (
							<Link className={classes.linkClass} to={{
								pathname: `/story/${data.title.replace(/[,-.–—"':?!$&;]/g, '').replace(/\s+/g, '-').toLowerCase()}`,
								story: data
							}}>
								<Grid container className={classes.newsCont} key={i}>
									{	matches ? (
										<Grid style={{ paddingRight: '.5rem' }} item md={5}>
											<Typography variant="h4" style={{ marginBottom: '2rem', fontFamily: 'Helvetica Compressed' }}>{data.title}</Typography>
											<Typography variant="body1" color="textSecondary" style={{ marginBottom: '2rem' }}>{data.details}</Typography>
											<Typography variant="button">{data.time}</Typography>
										</Grid>
										) : null
									}
									<Grid style={{ overflow: 'hidden' }} item xs={12} md={7}>
										<img src={data.img} alt="news" className={classes.imgClass} />
										{!matches ? <h2 style={{ fontSize: '1.85rem', padding: '0 1rem', fontFamily: 'Helvetica Compressed' }}>{data.title}</h2> : null}
									</Grid>
								</Grid>
							</Link>
						)
					)}
					</Carousel>
					) : (
						news.filter((data, i) => i === 0).map((data, i) => (
							<Link className={classes.linkClass} to={{
								pathname: `/story/${data.title.replace(/[,-.–"':?!$&;]/g, '').replace(/\s+/g, '-').toLowerCase()}`,
								story: data
							}}>
								<Grid key={i} style={{ marginTop: '.5rem', overflow: 'hidden' }} item xs={12} md={7}>
									<img src={data.img} alt="news" className={classes.imgClass} />
									<h2 style={{ fontSize: '1.85rem', padding: '0 1rem', fontFamily: 'Helvetica Compressed' }}>{data.title}</h2>
									<hr className={classes.smHr} />
								</Grid>
							</Link>
						))
					)
			}
			{
				!matches ? (
					<div style={{ position: 'relative', display: 'flex', width: '100%', overflow: 'auto', paddingTop: '1.1rem', marginBottom: '5rem' }}>
						{
							news.filter((data, i) => i > 0).map((data, i) => (
								<Link className={classes.linkClass} to={{
									pathname: `/story/${data.title.replace(/[,-.–"':?!$&;]/g, '').replace(/\s+/g, '-').toLowerCase()}`,
									story: data
								}}>
									<Grid key={i} className={classes.smGrid}>
										<img src={data.img} alt="news" className={classes.smImg} />
										<Typography variant="caption">{data.title}</Typography>
									</Grid>
								</Link>
							))
						}
					</div>
				) : null
			}
		</Grid>
	);
}
