import React, { useEffect } from "react";
import { Link } from 'react-router-dom';

// Material
import Typography from '@material-ui/core/Typography';
import Container from '@material-ui/core/Container';
import Grid from '@material-ui/core/Grid';
import { makeStyles, createStyles, useTheme } from '@material-ui/core/styles';
import useMediaQuery from '@material-ui/core/useMediaQuery';

import Paper from '@material-ui/core/Paper';
import Divider from '@material-ui/core/Divider';
import InputBase from '@material-ui/core/InputBase';
import IconButton from '@material-ui/core/IconButton';
import KeyboardArrow from '@material-ui/icons/KeyboardArrowRight';

// Comps
import { newsAll } from '../util/news'
import TopicsMap from '../components/topics/TopicsMap'
import Footer from '../components/Footer'

const useStyles = makeStyles((theme: Theme) => createStyles({
	...theme.spreadThis,
	background: {
		background: theme.palette.secondary.main,
		position: 'absolute',
		width: '100%',
		height: '50vh',
		top: 0,
		marginTop: '-2rem',
		zIndex: '-10'
	},
	topicCont: {
		marginTop: '2rem',
		background: 'white',
		padding: '2.5% 5%',
		[theme.breakpoints.down('sm')]: {
			paddingTop: '5%'
		}
	},
	topImg: {
		width: '100%',
		height: '400px',
		objectFit: 'cover',
		[theme.breakpoints.down('sm')]: {
			width: '75%',
			margin: 'auto',
			display: 'flex',
			height: '300px',
		},
		[theme.breakpoints.down('xs')]: {
			width: '100%',
			height: '200px',
		},
	},
	titleText: {
		margin: '1rem 0',
		textTransform: 'capitalize',
		fontFamily: '"Helvetica Compressed"',
		[theme.breakpoints.down('sm')]: {
			fontSize: '175%'
		}	
	},
	gridBtm: {
		marginTop: '3rem',
		[theme.breakpoints.up('lg')]: {
			paddingLeft: '4rem'
		},
		[theme.breakpoints.up('md')]: {
			paddingLeft: '2rem',
			marginTop: 0
		}
	},
	recentCont: {
		textTransform: 'capitalize',
		marginTop: '.5rem',
		marginBottom: '1.5rem',
		display: 'flex',
		width: '100%',
		flexWrap: 'inherit'
	},
	recentImg: {
		margin: 'auto .5rem',
		objectFit: 'cover',
		minWidth: '75px',
		maxWidth: '75px',
		height: '75px'
	},
	body: {
		display: 'flex',
		flexDirection: 'column'
	},
	subCont: {
		background: theme.palette.primary.dark,
		padding: '1.5rem',
		color: 'white',
		width: '80%',
		margin: '3rem auto 0'
	},
	paperClass: {
		marginTop: '1rem',
    padding: '2px 4px',
    display: 'flex',
    alignItems: 'center',
    borderRadius: 0
	},
  input: {
    marginLeft: theme.spacing(1),
    flex: 1,
  },
  iconButton: {
    padding: 10,
  },
  divider: {
    height: 28,
    margin: 4,
  },
}))

export default function(props) {

  useEffect(() => {
    document.title = 'MPH | Topics';
  }, []);

  const theme = useTheme();
  const classes = useStyles(props);
  const matches = useMediaQuery(theme.breakpoints.up('md'));

  const title = props.location.pathname.slice(8);

  const news = newsAll[title][0].array;

	return (
		<div style={{ position: 'relative' }}>
			<div className={classes.background}></div>
			<Container className={classes.topicCont} maxWidth="lg">
				<Typography variant="body1" style={{ marginBottom: '2rem', color: 'lightgray', textTransform: 'uppercase', fontWeight: 'bold' }}>{title}</Typography>
				<Grid container>
					<Grid item xs={12} md={7}>
						{
							news.filter((data, i) => i === 0).map((data, i) => (
								<Link key={i} className={classes.linkClass} to={{
									pathname: `/story/${data.title.replace(/[,-.–—"':?!$&;]/g, '').replace(/\s+/g, '-').toLowerCase()}`,
									story: data
								}}>
									<img src={data.img} alt={`${title} image`} className={classes.topImg} />
									<Typography variant="h4" className={classes.titleText}>{data.title}</Typography>
									<Typography style={{ textTransform: 'uppercase' }} variant="caption">{data.time}</Typography>
								</Link>
							))
						}
					</Grid>
					<Grid item xs={12} md={5}>
						<div className={classes.gridBtm}>
						{
							news.filter((data, i) => i > 0).map((data, i) => (
								<Link key={i} className={classes.linkClass} to={{
									pathname: `/story/${data.title.replace(/[,-.–—"':?!$&;]/g, '').replace(/\s+/g, '-').toLowerCase()}`,
									story: data
								}}>
									<Grid className={classes.recentCont} key={i} container>
										<img src={data.img} alt="recent-img" className={classes.recentImg} />
										<div className={classes.body}>
											<Typography variant="body1">{data.title}</Typography>
											<Typography style={{ marginTop: 'auto', textTransform: 'uppercase' }} variant="caption">{data.time}</Typography>
										</div>
									</Grid>
									{ news.filter((data, i) => i > 0).length !== i+1 ? <hr className={classes.newsHr} /> : null }
								</Link>
							))
						}
						<div className={classes.subCont}>
							<Typography style={{ fontWeight: 'bold', fontFamily: '"Open Sans"', marginBottom: '.5rem' }} variant="h6">On news, in your inbox!</Typography>
							<Typography variant="body2">Get updated with the latest news by joining our newsletter.</Typography>
						  <Paper className={classes.paperClass} component="form">
					      <InputBase
					        className={classes.input}
					        inputProps={{ 'aria-label': 'enter email' }}
					      />
					      <Divider className={classes.divider} orientation="vertical" />
					      <IconButton type="submit" className={classes.iconButton}>
					        <KeyboardArrow />
					      </IconButton>
						  </Paper>
						</div>
						</div>
					</Grid>
				</Grid>
				<TopicsMap title={title} />
			</Container>
			<Footer />
		</div>
	);
}
